import json
import math

# Get the filtered contingency table
filtered_contingency = locals()['var_functions.execute_python:68']['filtered_table']

# Convert to DataFrame for easier manipulation
import pandas as pd
df = pd.DataFrame(filtered_contingency).T

# Calculate row and column totals
row_totals = df.sum(axis=1)
col_totals = df.sum(axis=0)
grand_total = df.sum().sum()

# Calculate expected frequencies
expected = {}
chi_square = 0
contributions = {}

for hist_type in df.index:
    expected[hist_type] = {}
    contributions[hist_type] = {}
    for mut_status in df.columns:
        # Expected frequency Eij = (row_total * col_total) / grand_total
        row_total = row_totals[hist_type]
        col_total = col_totals[mut_status]
        expected_freq = (row_total * col_total) / grand_total

        expected[hist_type][mut_status] = expected_freq

        # Chi-square contribution = (Oij - Eij)^2 / Eij
        observed = df.loc[hist_type, mut_status]
        contribution = (observed - expected_freq) ** 2 / expected_freq
        contributions[hist_type][mut_status] = contribution
        chi_square += contribution

# Convert to regular Python types
result = {
    'chi_square_statistic': float(chi_square),
    'degrees_of_freedom': (df.shape[0] - 1) * (df.shape[1] - 1),
    'contingency_table': {k: {'No_Mutation': int(v['No_Mutation']), 'Mutation': int(v['Mutation'])} 
                         for k, v in filtered_contingency.items()},
    'expected_frequencies': {str(k): {str(k2): float(v2) for k2, v2 in v.items()} 
                            for k, v in expected.items()},
    'chi_square_contributions': {str(k): {str(k2): float(v2) for k2, v2 in v.items()} 
                                for k, v in contributions.items()}
}

print('__RESULT__:')
print(json.dumps(result))

